UPDATE enterprise_job_posting
   SET pending_revision_json = CAST(#{pendingRevisionJson} AS JSON),
       review_status = #{reviewStatus},
       review_memo = #{reviewMemo}
 WHERE id = #{id}

UPDATE enterprise_job_posting
   SET community_post_id = #{communityPostId}
 WHERE id = #{id}

mapper.select:
SELECT FROM enterprise_job_posting j JOIN users u ON u.id = j.company_user_id WHERE j.status = 'PUBLISHED' AND j.visibility = 'PUBLIC'
AND ( j.company_name LIKE CONCAT('%', #{keyword}, '%') OR j.title LIKE CONCAT('%', #{keyword}, '%') OR j.position_title LIKE CONCAT('%', #{keyword}, '%') OR j.job_category LIKE CONCAT('%', #{keyword}, '%') OR j.work_location LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY COALESCE(j.application_end_at, '2999-12-31') ASC, j.created_at DESC LIMIT #{limit}
